// Normalize either input mode into a common shape the agents can reason over.
const body = $json.body ?? $json;
const mode = body.mode;
const context = body.context || '';

let findings;
if (mode === 'order_level') {
  const stats = (body.stats || {}).core_stats || {};
  const cliff = (body.stats || {}).cliff || null;
  findings = {
    headline_metric: 'repeat purchase rate',
    your_value: stats.repeat_rate_pct,
    supporting: {
      total_customers: stats.total_customers,
      median_days_to_second_order: stats.median_days_to_second_order,
      m1_m2_cliff: cliff,
      discount_dependency: stats.discount_dependency || null,
      channel_repeat_rate: stats.channel_repeat_rate || null,
      category_mix: stats.category_mix || null
    }
  };
} else {
  findings = {
    headline_metric: 'flagged funnel metric changes',
    findings: (body.stats || {}).findings || []
  };
}

return [{ json: { mode: mode || 'metrics_snapshot', findings, context } }];

