// Parse the Compiler agent's JSON output and build a styled HTML report for PDF conversion.
let raw = $json.output;
let diag;
try {
  diag = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (e) {
  diag = {
    verdict_headline: 'Could not parse diagnosis',
    diagnosis_detail: String(raw).slice(0, 800),
    benchmark: {},
    plays: []
  };
}

const b = diag.benchmark || {};
const playsHtml = (diag.plays || []).map(p => `
  <div class="play">
    <div class="play-rank">${p.rank || ''}</div>
    <h3>${p.title || ''}</h3>
    <p class="impact">${p.estimated_impact || ''}</p>
    <p><b>Segment:</b> ${p.segment || ''}<br/><b>Trigger:</b> ${p.trigger || ''}<br/><b>Channel:</b> ${p.channel || ''}</p>
    <div class="msg">${p.sample_message || ''}</div>
  </div>
`).join('');

const html = `<!DOCTYPE html><html><head><meta charset="utf-8"><style>
body{font-family:Arial,sans-serif;max-width:800px;margin:40px auto;color:#1a1a1a;line-height:1.5;}
h1{font-size:24px;border-bottom:2px solid #333;padding-bottom:8px;}
h2{font-size:19px;margin-top:28px;color:#222;}
h3{font-size:15px;margin:6px 0;color:#222;}
.verdict{border-left:4px solid #C24632;padding:10px 16px;background:#faf7f6;margin:12px 0;}
.bench{margin:12px 0;font-size:13px;color:#444;}
.play{border:1px solid #ddd;border-radius:6px;padding:14px 16px;margin-bottom:12px;}
.play-rank{font-size:10.5px;letter-spacing:.08em;text-transform:uppercase;color:#666;}
.impact{font-size:12px;color:#2E7D6B;font-weight:600;margin:4px 0;}
.msg{background:#f1f4f2;border-left:3px solid #2E7D6B;padding:8px 12px;font-size:12.5px;margin-top:8px;}
p{margin:6px 0;font-size:13.5px;}
</style></head><body>
<p style="color:#666;font-size:12px;">Funnel Diagnostics — generated ${new Date().toISOString().split('T')[0]}</p>
<h1>${diag.verdict_headline || 'Diagnosis'}</h1>
<div class="verdict"><p>${diag.diagnosis_detail || ''}</p></div>
<h2>Benchmark</h2>
<div class="bench">${b.metric_label || 'Metric'}: your value ${b.your_value ?? 'n/a'} · category benchmark ${b.category_benchmark ?? 'n/a'} · best-in-class ${b.best_in_class ?? 'n/a'}</div>
<h2>Recommended plays</h2>
${playsHtml}
</body></html>`;

return [{ json: { diagnosis: diag, html } }];

// Recombine the parsed diagnosis (from before the PDF call) with the PDF.co response.
const diagnosis = $('Format Report HTML').first().json.diagnosis;
const pdfUrl = $json.url || ($json.body ? $json.body.url : null) || null;

return [{ json: { diagnosis, pdf_url: pdfUrl } }];
